import { Component, OnInit } from '@angular/core';
import { AuthService } from '../../core/services/auth.service';
import { SkillService, DepartmentService } from '../../core/services/api.services';
import { ToastService } from '../../core/services/toast.service';
import { Skill, Department } from '../../core/models';

@Component({ selector: 'app-skills', templateUrl: './skills.component.html' })
export class SkillsComponent implements OnInit {
  skills: Skill[] = [];
  filtered: Skill[] = [];
  departments: Department[] = [];
  loading = true;
  showForm = false;
  showDelConfirm = false;
  formMode: 'create' | 'edit' = 'create';
  selected: Skill | null = null;
  saving = false;
  searchTerm = '';
  filterCategory = '';
  form: any = { name: '', category: '' };

  categories: string[] = [];

  constructor(public auth: AuthService, private skillService: SkillService, private deptService: DepartmentService, private toast: ToastService) {}

  ngOnInit(): void {
    this.load();
    this.deptService.getAll().subscribe(r => { if (r.success) this.departments = r.data; });
  }

  load(): void {
    this.loading = true;
    this.skillService.getAll().subscribe(r => {
      if (r.success) {
        this.skills = r.data;
        this.categories = [...new Set(r.data.map(s => s.category || 'General').filter(Boolean))].sort();
        this.applyFilters();
      }
      this.loading = false;
    });
  }

  applyFilters(): void {
    this.filtered = this.skills.filter(s => {
      const matchSearch = !this.searchTerm || s.name.toLowerCase().includes(this.searchTerm.toLowerCase());
      const matchCat = !this.filterCategory || s.category === this.filterCategory;
      return matchSearch && matchCat;
    });
  }

  get groupedSkills(): { category: string; skills: Skill[] }[] {
    const groups: Record<string, Skill[]> = {};
    this.filtered.forEach(s => {
      const cat = s.category || 'General';
      if (!groups[cat]) groups[cat] = [];
      groups[cat].push(s);
    });
    return Object.entries(groups).map(([category, skills]) => ({ category, skills })).sort((a, b) => a.category.localeCompare(b.category));
  }

  openCreate(): void {
    this.formMode = 'create';
    this.form = { name: '', category: this.categories[0] || '' };
    this.showForm = true;
  }

  openEdit(s: Skill): void {
    this.formMode = 'edit';
    this.selected = s;
    this.form = { name: s.name, category: s.category || '' };
    this.showForm = true;
  }

  save(): void {
    if (!this.form.name) return;
    this.saving = true;
    const obs = this.formMode === 'create'
      ? this.skillService.create(this.form)
      : this.skillService.update(this.selected!.id, this.form);
    obs.subscribe({
      next: r => {
        this.saving = false;
        if (r.success) { 
          this.showForm = false; this.load(); 
          this.toast.showSuccess(this.formMode === 'create' ? 'Skill created successfully' : 'Skill updated successfully');
        } else { this.toast.showError(r.message || 'Failed to save skill'); }
      },
      error: err => { this.saving = false; this.toast.showError(err.error?.message || 'Error saving skill'); }
    });
  }

  confirmDelete(s: Skill): void { this.selected = s; this.showDelConfirm = true; }
  doDelete(): void {
    this.skillService.delete(this.selected!.id).subscribe({
      next: r => {
        if (r.success) { 
          this.showDelConfirm = false; this.load(); 
          this.toast.showSuccess('Skill deleted successfully');
        } else { this.toast.showError(r.message || 'Failed to delete skill'); }
      },
      error: err => this.toast.showError(err.error?.message || 'Error deleting skill')
    });
  }

  getCategoryColor(cat: string): string {
    const m: Record<string, string> = {
      Backend: 'badge-blue', Frontend: 'badge-purple', Database: 'badge-yellow',
      DevOps: 'badge-green', QA: 'badge-red', Design: 'badge-gray', 'UI/UX': 'badge-gray'
    };
    return m[cat] || 'badge-gray';
  }
}
<div class="fade-in">
  <div class="page-header">
    <div>
      <div class="page-title">Skills Library</div>
      <div class="page-subtitle">{{ skills.length }} skills across {{ categories.length }} categories</div>
    </div>
    <button class="btn btn-primary" (click)="openCreate()">+ Add Skill</button>
  </div>

  <div class="filter-bar">
    <div class="filter-search" style="flex:1">
      <span class="search-icon">🔍</span>
      <input class="form-control" placeholder="Search skills..." [(ngModel)]="searchTerm" (ngModelChange)="applyFilters()">
    </div>
    <select class="form-control" [(ngModel)]="filterCategory" (ngModelChange)="applyFilters()" style="width:160px">
      <option value="">All Categories</option>
      <option *ngFor="let c of categories" [value]="c">{{ c }}</option>
    </select>
  </div>

  <div *ngIf="loading" class="loading-wrap"><div class="spinner"></div></div>

  <div *ngIf="!loading && filtered.length === 0" class="card empty-state" style="padding:60px">
    <div class="empty-icon">◆</div>
    <div class="empty-title">No skills found</div>
  </div>

  <div *ngIf="!loading && filtered.length > 0">
    <div *ngFor="let group of groupedSkills" class="card" style="margin-bottom:16px">
      <div class="card-header" style="margin-bottom:14px">
        <div style="display:flex;align-items:center;gap:10px">
          <span class="badge" [ngClass]="getCategoryColor(group.category)">{{ group.category }}</span>
          <span style="font-size:13px;color:var(--text-muted)">{{ group.skills.length }} skill{{ group.skills.length !== 1 ? 's' : '' }}</span>
        </div>
      </div>
      <div style="display:flex;flex-wrap:wrap;gap:10px">
        <div *ngFor="let s of group.skills"
          style="display:flex;align-items:center;gap:8px;padding:8px 14px;border:1px solid var(--border);border-radius:var(--radius-sm);background:var(--bg-hover);transition:border-color 0.15s"
          [style.borderColor]="'var(--border)'"
          onmouseenter="this.style.borderColor='#93c5fd'"
          onmouseleave="this.style.borderColor='var(--border)'">
          <span style="font-weight:600;font-size:13px;color:var(--text-primary)">{{ s.name }}</span>
          <div style="display:flex;gap:4px;margin-left:4px">
            <button class="btn btn-icon btn-sm" style="padding:3px 6px;font-size:11px" (click)="openEdit(s)" title="Edit">✏</button>
            <button class="btn btn-icon btn-sm" style="padding:3px 6px;font-size:11px;color:var(--danger)" (click)="confirmDelete(s)" title="Delete">✕</button>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>

<!-- Form Modal -->
<div class="modal-overlay" *ngIf="showForm" (click)="showForm=false">
  <div class="modal modal-sm" (click)="$event.stopPropagation()">
    <div class="modal-header">
      <div class="modal-title">{{ formMode === 'create' ? 'Add Skill' : 'Edit Skill' }}</div>
      <button class="modal-close" (click)="showForm=false">×</button>
    </div>
    <div class="modal-body">
      <div class="form-group">
        <label class="form-label">Skill Name *</label>
        <input class="form-control" [(ngModel)]="form.name" placeholder="e.g. Spring Boot">
      </div>
      <div class="form-group">
        <label class="form-label">Category</label>
        <div style="display:flex;gap:8px">
          <select class="form-control" [(ngModel)]="form.category" style="flex:1">
            <option value="">Select category...</option>
            <option *ngFor="let c of categories" [value]="c">{{ c }}</option>
          </select>
        </div>
        <div style="margin-top:8px">
          <input class="form-control" [(ngModel)]="form.category" placeholder="Or type a new category...">
        </div>
      </div>
    </div>
    <div class="modal-footer">
      <button class="btn btn-outline" (click)="showForm=false">Cancel</button>
      <button class="btn btn-primary" (click)="save()" [disabled]="saving || !form.name">
        {{ saving ? 'Saving...' : (formMode === 'create' ? 'Add Skill' : 'Save') }}
      </button>
    </div>
  </div>
</div>

<!-- Delete Confirm -->
<div class="modal-overlay" *ngIf="showDelConfirm" (click)="showDelConfirm=false">
  <div class="modal modal-sm" (click)="$event.stopPropagation()">
    <div class="modal-header"><div class="modal-title" style="color:var(--danger)">Delete Skill</div></div>
    <div class="modal-body">
      <p>Delete skill "<strong>{{ selected?.name }}</strong>"?</p>
      <p style="margin-top:8px;font-size:12px;color:var(--text-muted)">This will remove the skill from all users and tasks that use it.</p>
    </div>
    <div class="modal-footer">
      <button class="btn btn-outline" (click)="showDelConfirm=false">Cancel</button>
      <button class="btn btn-danger" (click)="doDelete()">Delete</button>
    </div>
  </div>
</div>
